input.command:
powershell -NoProfile -ExecutionPolicy Bypass -Command "
$log = 'C:\Users\Administrator\.cursor\projects\empty-window\install-vsix-result.txt'
$vsix = 'c:\Users\Administrator\Desktop\cursor-free-2.4.11.vsix'
$sb = New-Object System.Text.StringBuilder
function Log([string]$s) { [void]$sb.AppendLine($s) }
Log '=== VSIX Install Log ==='
Log ('Time: ' + (Get-Date -Format o))
Log ('Step 1 - File exists: ' + (Test-Path -LiteralPath $vsix))
if (Test-Path -LiteralPath $vsix) { $i = Get-Item -LiteralPath $vsix; Log ('  FullName: ' + $i.FullName); Log ('  Length: ' + $i.Length) }
$cliCandidates = @(
  (Join-Path $env:LOCALAPPDATA 'Programs\cursor\resources\app\bin\cursor.cmd'),
  (Join-Path $env:LOCALAPPDATA 'Programs\cursor\Cursor.exe'),
  (Join-Path $env:LOCALAPPDATA 'Programs\Microsoft VS Code\bin\code.cmd'),
  (Join-Path ${env:ProgramFiles} 'Microsoft VS Code\bin\code.cmd')
)
Log 'Step 2 - CLI candidates:'
foreach ($c in $cliCandidates) { Log ('  ' + $c + ' -> ' + (Test-Path -LiteralPath $c)) }
$cmd = $null
foreach ($c in $cliCandidates) { if (Test-Path -LiteralPath $c) { $cmd = $c; break } }
if (-not $cmd) {
  $gc = Get-Command cursor -ErrorAction SilentlyContinue
  if ($gc) { $cmd = $gc.Source }
}
if (-not $cmd) {
  $gc = Get-Command code -ErrorAction SilentlyContinue
  if ($gc) { $cmd = $gc.Source }
}
if (-not $cmd) { Log 'ERROR: No cursor/code CLI found'; $sb.ToString() | Set-Content -LiteralPath $log -Encoding UTF8; exit 1 }
Log ('Selected CLI: ' + $cmd)
$argList = @('--install-extension', $vsix)
$exe = $cmd
if ($cmd -like '*.exe') { $psi = $exe + ' ' + ($argList -join ' ') } else { $psi = '& ' + [char]34 + $exe + [char]34 + ' ' + ($argList | ForEach-Object { [char]34 + $_ + [char]34 }) -join ' ' }
Log ('Exact command: ' + $psi)
try {
  $p = Start-Process -FilePath $exe -ArgumentList $argList -Wait -PassThru -NoNewWindow -RedirectStandardOutput ($log + '.stdout') -RedirectStandardError ($log + '.stderr')
  Log ('Exit code: ' + $p.ExitCode)
  if (Test-Path ($log + '.stdout')) { Log '--- stdout ---'; Log (Get-Content -LiteralPath ($log + '.stdout') -Raw) }
  if (Test-Path ($log + '.stderr')) { Log '--- stderr ---'; Log (Get-Content -LiteralPath ($log + '.stderr') -Raw) }
  $sb.ToString() | Set-Content -LiteralPath $log -Encoding UTF8
  exit $p.ExitCode
} catch {
  Log ('EXCEPTION: ' + $_.Exception.Message)
  $sb.ToString() | Set-Content -LiteralPath $log -Encoding UTF8
  exit 2
}
"
